class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        close_to_open = {')': '(', ']': '[', '}': '{'}
        for char in s:
            if char in close_to_open:
                if not stack:
                    return False
                top = stack.pop()
                if close_to_open[char] != top:
                    return False
            else:
                stack.append(char)
        return len(stack) == 0

